# Auto-generated data file for Shinylive compatibility
import pandas as pd

DATA = [{'Mosquito Name and First Describer': 'Anopheles Meigen, 1818', 'Full Reference': 'Meigen, J.W. (1818) Systematische Beschreibung der Bekannten Europäischen Zweiflügeligen Insekten. 1. xxxvi + 334pp. Aachen. Forstmann.', 'Etymology (Latin/Greek)': 'Greek, anopheles = useless, troublesome', 'Full Description': "Meigen defines his genus in the last line of his description on page 10 saying that the name Anopheles means troublesome 'Der Namen Anopheles bedeutet beschwerlich'. He titles the description 'Gabelmükke ANOPHELES', literally forked or bifurcate gnat, used in the sense of describing the mouthparts."}, {'Mosquito Name and First Describer': 'Anopheles algeriensis Theobald, 1903', 'Full Reference': 'Theobald, F.V. (1903) A monograph of the Culicidae or mosquitoes. 3. xvii+359 pp. London. British Museum (Natural History).', 'Etymology (Latin/Greek)': 'Algeria = country name', 'Full Description': "Theobald describes his species on page 21, but his only references to Algeria are 'Habitat-Algeria (Dr. Sergent).' and the caption to his Figure 9 'Wing of Anopheles Algeriensis. n.sp. Algeria.'"}, {'Mosquito Name and First Describer': 'Anopheles atroparvus van Thiel, 1927', 'Full Reference': "Van Thiel, P.H. (1927) Sur l'origine des variations de taille de l'Anopheles maculipennis dans les Pays Bas. Bulletin de la Société de Pathologie exotique 10, 366-390.", 'Etymology (Latin/Greek)': 'Latin, atro (ater) = black; parvus = small', 'Full Description': "On page 389, van Thiel names his variety 'je propose pour le type de Bolsward (Friesland, Holland) le nom de Anopheles maculipennis. MEIGEN var. atroparvus novo var.' He notes that the Bolsward population are small and that there is a colour difference, the segments being greyish with posterior parts often black."}, {'Mosquito Name and First Describer': 'Anopheles beklemishevi Stegnii & Kabanova, 1976', 'Full Reference': 'Stegnii, V.N. & Kabanova, V.M (1978) Cytoecological study of indigenous populations of the malaria mosquito in the territory of the USSR 1. Identification of a new species of Anopheles in the maculipennis complex by the cytodiagnostic method. Meditsinskaya Parazitologiya i Parazitarnye Bolezni 45, 192-198.', 'Etymology (Latin/Greek)': 'Patronymic dedication to V.N. Beklemishev', 'Full Description': "On Page 198 this species is dedicated to the Russian scientist Vladimir Nikolaievitch Beklemishev 'In honour of the distinguished Soviet scientist and malariologist V.N. Beklemishev, the authors name the new species Anopheles beklemishevi Stegni and Kabanova sp.n.' V.N. Beklemishev (1890-1962) was a distinguished malariologist in the former Soviet Union and a member of the WHO Expert Committee on malaria."}, {'Mosquito Name and First Describer': 'Anopheles claviger (Meigen, 1804)', 'Full Reference': 'Meigen, J.W. (1804) Klassifikation und Beschreibung der Europäischen Zweiflügeligen Insekten (Diptera Linn.). 1. xxviii+152pp. Braunschweig. Reichard.', 'Etymology (Latin/Greek)': 'Latin, clava = club; -ger, suffix = bearing, from gerere = to bear', 'Full Description': "Originally described as Culex claviger. On page 4 Meigen describes the club-shaped palps of the male in both Latin and German: '...palpi maris claviformibus ...' and 'Fresspitzen des Männchens keulförmig'."}, {'Mosquito Name and First Describer': 'Anopheles hyrcanus (Pallas, 1771)', 'Full Reference': 'Pallas, P.S. (1771) Reise Durch Verschiedene Provinzen des Russischen Reichs. 1. 504pp. St Petersburg.', 'Etymology (Latin/Greek)': 'Hyrcania = ancient land bordering southeastern shore of the Caspian Sea', 'Full Description': "Pallas describes Culex caspius and Culex hyrcanus on page 475 saying of the former 'Versus mare Caspium in paludosis salsis, cum vexati infestissimus' and of Cx. hyrcanus 'Comes priovis, rarior sed Ferocior'. He makes no other reference to the Caspian Sea but clearly has the ancient land of Hyrcania in mind in naming the species. Today this area corresponds with an area in northern Iran, bordering the southeastern shore of the Caspian Sea."}, {'Mosquito Name and First Describer': 'Anopheles messeae Falleroni, 1926', 'Full Reference': "Falleroni, D. (1926) Fauna anofelica italiana e suo 'habitat' (Paludi, risaie, canali). Metodi di lotta contro la malaria. Rivista di Malariologia 5, 553-593.", 'Etymology (Latin/Greek)': 'Patronymic dedication to Count Alessandro di Federico Messea', 'Full Description': "Falleroni described messeae as a variety of An. claviger. Falleroni dedicated the species to Count Alessandro di Federico Messea, a notable Italian public health administrator who conducted campaigns against tuberculosis, cancer and malaria. On page 564 he states: 'Le ho dedicate ad Messea, direttore Generale e A. Labranca, Capo Divisione della Sanità Pubblica, in omaggio alle loro benemerenze nella lotta contro la malaria nel nostro Paese'."}, {'Mosquito Name and First Describer': 'Anopheles plumbeus Stephens, 1828', 'Full Reference': 'Stephens, J.F. (1828) Note on the foregoing paper, with a description of a new species of Anopheles. Zoological Journal 3, 502-504.', 'Etymology (Latin/Greek)': 'Latin, plumbeus = leaden, lead coloured', 'Full Description': "This species was described by Haliday (1828) but he did not name it. Haliday described it on page 501 as '3.A._? A smaller species. Thorax lead colour, the sides with a blackish line...' In the following article Stephens states '... The addition of a third species of Anopheles, proves incontestably how limited our knowledge of species remains..... the above may be called An. plumbeus ...'"}, {'Mosquito Name and First Describer': 'Anopheles labranchiae Falleroni, 1926', 'Full Reference': "Falleroni, D. (1926) Fauna anofelica italiana e suo 'habitat' (Paludi, risaie, canali). Metodi di lotta contro la malaria. Rivista di Malariologia 5, 553-593.", 'Etymology (Latin/Greek)': 'Patronymic dedication to Antonio Labranca', 'Full Description': "Falleroni dedicated An. claviger, Mg., var. labranchiae Falleroni to Antonio Labranca. On page 564 he states: 'Le ho dedicate ad... A. Labranca, Capo Divisione della Sanità Pubblica, in omaggio alle loro benemerenze nella lotta contro la malaria nel nostro Paese'. Antonio Labranca was born in 1876 in Trinitapoli, Foggia, and was awarded a medical degree from the University of Rome in 1900. He then worked in professor Celli's malaria laboratory before entering the public health department (Sanità Pubblica) in 1904 where he remained for 43 years as a medical administrator attaining the position vice-director of Sanità Pubblica."}, {'Mosquito Name and First Describer': 'Anopheles maculipennis Meigen, 1818', 'Full Reference': 'Meigen, J.W. (1818) Systematische Beschreibung der Bekannten Europäischen Zweiflugeligen Insekten 1, xxxvi + 334 pages. Aachen. Forstmann.', 'Etymology (Latin/Greek)': 'Latin, macula = spot; penna = wings; -is = adjectival suffix', 'Full Description': "Meigen defines the species in the first line of his account on page 11: 'Flügel mit fünf braunen Punkten.' And repeats this in Latin: 'Alis punctis quinque fuscis.' Later he expands his description: 'Flügel mit fünf braunen Punkten, welche die nämliche Lage haben wie bei Culex annulatus.'"}, {'Mosquito Name and First Describer': 'Anopheles marteri Senevet and Prunnelle, 1927', 'Full Reference': "Senevet, G. & Prunnelle, M. (1927) Une nouvelle espèce d'anophèle en Algérie, Anopheles marteri n. sp. Archives de l'Institut Pasteur d'Algérie 5, 529-533.", 'Etymology (Latin/Greek)': 'Patronymic dedication to Marie Louise Marter', 'Full Description': "Georges Senevet, one of the greatest of French entomologists named this species after his wife Marie Louise Marter who originated from Camp du Maréchal in Algeria. Tragically Marie died of pneumonia a year after their marriage and was buried in her hometown. On a visit to the grave he discovered the mosquito which he named An. marteri. His only reference is to the location of the type: 'Nous avons trouvé des exemplaires aux saisons indiquées à Camp du Maréchal'."}, {'Mosquito Name and First Describer': 'Anopheles melanoon Hackett, 1934', 'Full Reference': 'Hackett, L.W. (1934) The present status of our knowledge of the subspecies of Anopheles maculipennis. Transactions of the Royal Society of Tropical Medicine and Hygiene 28, 109-128.', 'Etymology (Latin/Greek)': 'Greek, melas, melanos = black; oon = egg', 'Full Description': "The reason for naming this species is quite clear, the name being derived from the Greek melas, melanos - black and oon - egg. Hackett says 'The black egg, though recognised from the beginning as a variety by Falleroni and subsequent authors, has been considered until recently a modification of messeae... It is useful, however, to continue to separate the black-egg type from messeae, and for convenience we have given it the name melanoon'."}, {'Mosquito Name and First Describer': 'Anopheles petragnani Del Vecchio, 1939', 'Full Reference': 'Del Vecchio, G. (1939) Sulle varietà de A. claviger (bifurcatus) nota 1. Revista di Parassitologia 3, 27-37', 'Etymology (Latin/Greek)': 'Patronymic dedication to Professor Giovanni Petragnani', 'Full Description': "This species was named, originally as a variety of Anopheles claviger, after Professor Giovanni Petragnani (1893-1968) who made important contributions to the eradication of malaria while working at the University of Cagliari in Sardinia and as Director General of Public Health. Del Vecchio states on page 27, '...in omaggio a S.E. Giovanni Petragnani, direttore generale della Sanità Pubblica, il quale tanto impulso ha dato e dà ai servizi sanitari del Regno, con particolare riguardo a quelli anti-malarici...'"}, {'Mosquito Name and First Describer': 'Anopheles sacharovi Favre, 1903', 'Full Reference': 'Favre, V.V. (1903) An attempt at the study of malaria in Russia. Kharkov. 344pp.', 'Etymology (Latin/Greek)': 'Patronymic dedication to Nikolai Alekseevich Sacharov', 'Full Description': "Although clearly named by Favre after his mentor, Nikolai Alekseevich Sacharov (1852-1927), there is no reference to this in the description of the species. On page 189 he says, '...I am provisionally calling it Anopheles sacharovi...' Sacharov was a medical doctor and researcher and became medical consultant for the railway and was especially involved with the problem of malaria associated with the construction of the Transcaucasian Railroad."}, {'Mosquito Name and First Describer': 'Anopheles subalpinus Hackett and Lewis, 1935', 'Full Reference': 'Hackett, L.W. & Lewis, D.J. (1935) A new variety of Anopheles maculipennis in southern Europe. Revista di Malariologia 14, 377-383.', 'Etymology (Latin/Greek)': 'Latin, sub = below; alpinus = alpine', 'Full Description': "This species was described from Albania as '...a separate race, which since it has never been reported from northern Europe, we have called Anopheles maculipennis subalpinus. var. nov.' The name originates from the Latin sub meaning below and apparently used here in the sense of south of the Alps."}, {'Mosquito Name and First Describer': 'Subgenus Cellia Theobald, 1902', 'Full Reference': 'Theobald, F.W. (1902) The classification of the Anophelina. Journal of Tropical Medicine 5, 181-183.', 'Etymology (Latin/Greek)': 'Patronymic dedication to Angelo Celli', 'Full Description': "Theobald dedicated this taxon on page 181 to the Italian malariologist Angelo Celli (1857-1914) although he makes no reference to him in the article. However Blanchard (1905) says (page 24) 'Genre dédié au professeur A. Celli de l'Université de Rome'. Celli was a contemporary of Ross and Grassi and made significant contributions to the study of malaria and other areas of public health."}, {'Mosquito Name and First Describer': 'Anopheles cinereus Theobald, 1901', 'Full Reference': 'Theobald, F.V. (1901) A monograph of the Culicidae or mosquitoes. Volume 1. 424pp. London. British Museum (Natural History).', 'Etymology (Latin/Greek)': 'Latin, cinereus = ash-coloured, grey', 'Full Description': "Theobald makes a number of references on pages 161-163 to the ash-grey colour of this mosquito: '...Head black, an ashy-grey border round the eyes...thorax with a broad ashy-grey line in the middle... the median grey area covered with long whitish hair-like scales...'"}, {'Mosquito Name and First Describer': 'Anopheles multicolor Cambouliu, 1902', 'Full Reference': "Cambouliu, M. (1902) Contribution à l'étude des Anopheles de l'isthme de Suez. Compte Rendu de l'Académie des Sciences, Paris 135, 704-706.", 'Etymology (Latin/Greek)': 'Latin, multus = many; color = colour', 'Full Description': "Cambouliu described An. multicolor on page 704 noting the many attractive colours of the species: 'Trompe noire, à olive beige... de minces anneaux blonds... un petite bouquet de poils noirs... ailes gris clair, transparentes, avec six petites taches noires entrecoupant le costa et les premières nervures... trainées bleu et or le long des autres nervures... visibles plutôt sur fond noir.'"}, {'Mosquito Name and First Describer': 'Anopheles sergentii Theobald, 1907', 'Full Reference': 'Theobald, F.V. (1907) A monograph of the Culicidae or mosquitoes. Vol. 4. 639 pp. London. British Museum (Natural History).', 'Etymology (Latin/Greek)': 'Patronymic dedication to Dr. Edmond Sergent', 'Full Description': "Theobald describes this mosquito on pages 68 and 69. The only reference to the naming of this mosquito is 'Habitat-, Algeria (Dr E. Sergent)'. This is believed to refer to Edmond Sergent (1876-1969) and not his brother, Etienne, although both worked in Algeria at the Pasteur Institute. Edmond is referred to by Theobald on page vii of this Monograph and is known to have collected mosquitoes and sent them to Theobald."}, {'Mosquito Name and First Describer': 'Anopheles superpictus Grassi, 1899', 'Full Reference': "Grassi, G.B. (1899) Ancora sulla malaria. Atti dell'Accademia Nazionale dei Lincei. Rendiconti 8, 559-561.", 'Etymology (Latin/Greek)': 'Latin, super = remaining, besides, moreover; pictus = ornate, decorated', 'Full Description': 'This species was described from Italy in a footnote on page 560 by Grassi to differentiate it from pictus and pseudopictus, both presently regarded as synonyms of hyrcanus. He was convinced that this was an additional form and named it superpictus to distinguish it from the other two.'}, {'Mosquito Name and First Describer': 'Aedes Meigen, 1818', 'Full Reference': 'Meigen, J.W. (1818) Systematische Beschreibung der bekannten europäischen zweiflügeligen Insekten. Vol. 1. xxxvi + 334 pp. Aachen. Forstmann.', 'Etymology (Latin/Greek)': 'Greek, aedes = distasteful, disagreeable, unpleasant, troublesome', 'Full Description': "Meigen names his genus on page 13, 'Schnökkenmükke AEDES, Hoffmgg'. Meigen describes the characteristics of his genus in both German and Latin and ends with an explanation of his generic name, saying that it is derived from the Greek meaning troublesome and that it was found in the collection of Hoffmannsegg, 'Den Gattungsnamen hat der Hr Graf v. Hoffmannsegg, in dessen Sammlung sie sich befindet, aus dem Griechischen beschwerlich gebildet'."}, {'Mosquito Name and First Describer': 'Aedes cinereus Meigen, 1818', 'Full Reference': 'Meigen, J.W. (1818) Systematische Beschreibung der bekannten europäischen zweiflügeligen Insekten. Vol. 1. xxxvi + 334 pp. Aachen. Forstmann.', 'Etymology (Latin/Greek)': 'Latin, cinereus = ash-coloured, grey', 'Full Description': "Like the genus Aedes, Meigen ascribes this species to Hr. Graf v. Hoffmannsegg, the collector of the material examined. Despite naming the species cinereus he was not convinced about its colour, noting that it is more brown than grey 'Diese einzige Art ist mehr braun als grau' (p 13). In a later description he also notes the grey wings 'die Flügel graulich' but gives its general coloration as 'schwarzbraun'."}, {'Mosquito Name and First Describer': 'Aedes geminus Peus, 1970', 'Full Reference': 'Peus, F. (1970) Bemerkenswerte Mücken am Tegeler Fließ. Berliner Naturschutzblätter. Special Number (May), 18-26.', 'Etymology (Latin/Greek)': 'Latin, geminus = twin', 'Full Description': 'On pages 21-24 Peus describes Aedes geminus and compares it with Ae. cinereus using both text, illustrations and a key. He places both species in the cinereus group of the subgenus Aedes, and indicates their close affinity by naming the new species geminus, the twin of cinereus.'}, {'Mosquito Name and First Describer': 'Aedes esoensis rossicus Dolbeskin, Gorickaja & Mitrofanova, 1930', 'Full Reference': "Yamada, S. (1921) Description of ten new species of Aedes found in Japan, with notes on the relation between some of these mosquitoes and the larva of Filaria bancrofti Cobbold. Annotationes Zoologicae Japonenses 10, 45-81. / Dolbeskin, B., Gorickaja, V. & Mitrofanova, J. (1930) Beschreibung einer neuen Art der Gattung Aedes (n. sp.) aus Osteuropa. Magazin de Parasitologie du Musée Zoologique de l'Académie des Sciences de l'URSS [Leningrad] 1, 253-260.", 'Etymology (Latin/Greek)': 'esoensis: from Ezo (ancient name for Hokkaido), -ensis = place where found; rossicus: from Rossiya (Russia), -icus = belonging to', 'Full Description': 'Yamada named Aedes esoensis from specimens collected from the islands of Hokkaido (Japan) and Sakhalin. Hokkaido was formerly known as Ezo or Yezo. Aedes rossicus was described from Orenburg and Perm in Russia and from Dnepropetrovsk in Ukraine, and was reduced to subspecies status by Peus (1972). The use of the name rossicus derives from the country name Rossiya and the suffix -icus, meaning belonging to or pertaining to a locality.'}, {'Mosquito Name and First Describer': 'Subgenus Aedimorphus Theobald, 1903', 'Full Reference': 'Theobald, F.V. (1903) A monograph of the Culicidae or mosquitoes. Vol. 3. xvii + 359 pp. London. British Museum (Natural History).', 'Etymology (Latin/Greek)': 'From genus Aedes (Meigen, 1818) and Greek morphos = form', 'Full Description': "Theobald erected the genus Aedimorphus for Aedimorphus domesticus, previously Uranotaenia domestica Theobald, 1901. He remarks on the distinctions from Aedes yet obviously considers his new taxon to be close to Aedes, '...The genus differs from others near Aedes, in (1) the presence of mixed head scales and flat scutellar ones, and (2) in the Uranotaenia-like appearance of the thorax, but differs from the latter in having long fork-cells and no flat thoracic scales' (p 290)."}, {'Mosquito Name and First Describer': 'Aedes vexans (Meigen, 1830)', 'Full Reference': 'Meigen, J.W. (1830) Systematische Beschreibung der bekannten europäischen zweiflügeligen Insekten. Vol. 6. xi + 401 pp. Hamm. Schulz.', 'Etymology (Latin/Greek)': 'Latin, vexare = to annoy, injure', 'Full Description': 'Meigen describes his species in both Latin and German on pages 241 and 242 under the name of Culex Vexans. He noted its brown coloration, abdomen with white patches and, like Culex (=Aedes) annulipes, tarsi with white rings. Having just named a species (annulipes) on the basis of its ringed tarsi, Meigen was presumably forced to find another name and chose to use vexans to indicate the annoying and injurious qualities of this species.'}, {'Mosquito Name and First Describer': 'Aedes vittatus (Bigot, 1861)', 'Full Reference': 'Bigot, J.M.F. (1861) Trois diptères nouveaux de la Corse. Annales de la Société Entomologique de France (4th series) 1, 227-229.', 'Etymology (Latin/Greek)': 'Latin, vittatus = bound with a fillet or chaplet, from vitta (-ae) ribbon, band, fillet', 'Full Description': "Bigot describes this species on the first page of his article: '1. CULEX VITTATUS (nov. spec.)'. He describes the new species as being generally deep black with white markings. He especially notes the white rings on the legs and, although not referring to vittatus specifically, it would appear that the presence of the distinctive white ring on the tibiae led Bigot to adopt this specific name."}, {'Mosquito Name and First Describer': 'Subgenus Finlaya Theobald, 1903', 'Full Reference': 'Theobald, F.V. (1903) A monograph of the Culicidae or mosquitoes. Vol. 3. xvii + 359 pp. London. British Museum (Natural History).', 'Etymology (Latin/Greek)': 'Patronymic dedication to Dr. Carlos Juan Finlay', 'Full Description': "Theobald describes 'Finlaya novogen.' on page 283 and remarks 'I have named this genus after Dr Finlay, the originator of the yellow-fever mosquito theory.' Carlos Juan Finlay proposed the yellow-fever mosquito theory in 1881 and in 1903, when the generic name was dedicated to him, was Chief Sanitary Officer of Cuba. Finlay was born in Puerto Principe, Cuba on December 3rd 1833. In 1855 he received the degree of M.D. from Jefferson Medical College, Philadelphia. He died in Havana, Cuba on August 20th 1915."}, {'Mosquito Name and First Describer': 'Aedes echinus (Edwards, 1920)', 'Full Reference': 'Edwards, F.W. (1920) Mosquito notes. Bulletin of Entomological Research 10, 129-137.', 'Etymology (Latin/Greek)': 'Latin, echinus = sea urchin / spiny', 'Full Description': "Edwards describes this species on pages 133-134 under the heading 'Ochlerotatus (Finlaya) echinus sp. nov.' He describes the female that was raised from a larva collected in Macedonia and differentiates it from Ochlerotatus (now Aedes) geniculatus. He notes that the larva is very different from O. geniculatus but does not describe it. However, it is the form of the larva that clearly led to the use of the name echinus. The fourth instar larva has unusually strongly developed thoracic and abdominal setae, which are stellately branched giving the appearance of a hedgehog."}, {'Mosquito Name and First Describer': 'Aedes geniculatus (Olivier, 1791)', 'Full Reference': 'Olivier, G.A. (1791) Encyclopédie méthodique. Histoire naturelle. Insectes. Vol. 6. 704 pp. Paris, Panckoucke.', 'Etymology (Latin/Greek)': 'Latin, geniculatus = having a knee, jointed', 'Full Description': "Olivier described Culex geniculatus as 'COUSIN genicule' on page 134 and continues in Latin and French, 'Culex... geniculis albis' and 'Les pattes sont noirâtres, avec la base des cuisses et le genou blancs...' Indeed Ae. geniculatus is readily recognised by its dark legs and the conspicuous whiteness of the knee-joints (tibia-femur joint) and the proximal areas of the thighs (femora)."}, {'Mosquito Name and First Describer': 'Aedes gilcolladoi Villa, Rodriguez & Llera, 1985', 'Full Reference': 'Villa, A.S-C., Rodriguez, J.A.R. & Llera, J.L.G. (1985) Estudio de la larva de cuarto estado de las especies del subgénero Finlaya (Diptera, Culicidae) de España Peninsular. Actas do Congreso Ibérico de Entomología. Boletim da Sociedade Portuguesa de Entomología 1 (Supplemento 1), 439-448.', 'Etymology (Latin/Greek)': 'Patronymic dedication to J. Gil Collado', 'Full Description': 'This species was differentiated from Aedes echinus and Ae. geniculatus in Spain on characters of larval chaetotaxy. It was named after the Spanish mosquito researcher J. Gil Collado, who was one of the earliest workers to describe the Culicidae of Spain and to record the presence of Aedes geniculatus and Ae. echinus in the Spanish fauna. He published a number of major papers from the mid 1920s until the very late 1950s.'}, {'Mosquito Name and First Describer': 'Ochlerotatus Lynch-Arribalzaga, 1891', 'Full Reference': 'Lynch-Arribalzaga, F. (1891) Dipterologia argentina. Revista del Museo de La Plata 1, 345-377; 2, 131-172.', 'Etymology (Latin/Greek)': 'Greek, ochleros = troublesome; Greek, -tatos = superlative', 'Full Description': "This article by Lynch-Arribalzaga is in two parts. In the first section on page 374 Ochlerothatus (sic) is given in a key to genera and in the continuation of the work (page 143) the then genus is described and the name explained '...Ochlerotatus, nov. gen. Ab. ochleros molestus (superl. otatos)...' The Latin equivalent of ochleros, i.e. molestus, is also given."}, {'Mosquito Name and First Describer': 'Aedes annulipes (Meigen, 1830)', 'Full Reference': 'Meigen, J.W. (1830) Systematische Beschreibung der bekannten europäischen zweiflügeligen Insekten 6. xi + 401pp. Hamm. Schulz.', 'Etymology (Latin/Greek)': 'Latin, annulus = ring; Latin, pes = foot', 'Full Description': "Meigen describes his species (as Culex annulipes) on page 241 making reference to the brown feet with white rings in both Latin and German: '...tarsis fuscis albo annulatis...' and 'Füsse braun, mit weissen Ringen...'"}, {'Mosquito Name and First Describer': 'Aedes atropalpus (Coquillett, 1902)', 'Full Reference': 'Coquillett, D.W. (1902) Three new species of Culex. The Canadian Entomologist 34, 292-293.', 'Etymology (Latin/Greek)': 'Latin, atro (ater) = black; palpus = palp, feeler', 'Full Description': "Under the heading 'Culex atropalpus, new species' on page 292, Coquillett provides a full description of the female. Regarding the palps he says, 'scales of palpi black', indicating the basis for his choice of epithet."}, {'Mosquito Name and First Describer': 'Aedes behningi Martini, 1926', 'Full Reference': 'Martini, E. (1926) Über die Steckmücken der Umgebung von Saratow. Arbeiten der Biologischen Wolga-Station 8, 189-277.', 'Etymology (Latin/Greek)': 'Patronymic dedication to Arvid Liberovich Behning', 'Full Description': 'Although there is no reference to the naming of the mosquito in the paper, it was clearly dedicated to Arvid Liberovich Behning (1890-1943) who was the Director of the Volga Biological Station in Saratov from 1912 until 1926. Martini collected his new species from Saratov, situated on the River Volga, and published the account of his discovery in the journal of the Volga Biological Station. Behning was an expert in Crustacea and on many other animal taxa from the River Volga.'}, {'Mosquito Name and First Describer': 'Aedes berlandi Séguy, 1921', 'Full Reference': "Séguy, E. (1921) Description d'un nouveau moustique Français du groupe de l'Aedes Mariae et synopsis des espèces de ce groupe. Bulletin de la Société Entomologique de France 1921, 192-195.", 'Etymology (Latin/Greek)': 'Patronymic dedication to Monsieur L. Berland', 'Full Description': "On page 194 of his article Séguy states clearly the part played by Monsieur Berland in the discovery of this new species, 'La première a été capturée par M. L. BERLAND dans le laboratoire d'Entomologie du Muséum, 55, rue de Buffon, le 7-5; vers 15 heures (1921).'"}, {'Mosquito Name and First Describer': 'Aedes cantans (Meigen, 1818)', 'Full Reference': 'Meigen, J.W. (1818) Systematische Beschreibung der bekannten europäischen zweiflügeligen Insekten 1. xxxvi + 334pp. Aachen. Forstmann.', 'Etymology (Latin/Greek)': 'Latin, cantans = singing', 'Full Description': "Meigen's descriptions of this species (as Culex cantans), in Latin and German, contain no reference to the sound produced in flight, which influenced his naming of this species. In the title of this description Meigen once again ascribes the species to the collector 'Hrn. Grafen v. Hoffmannsegg' as follows: 'Cul. cantans. Hoffmgg' (p 6)."}, {'Mosquito Name and First Describer': 'Aedes caspius (Pallas, 1771)', 'Full Reference': 'Pallas, P.S. (1771) Reise durch verschiedene Provinzen des Russischen Reichs 1. 504pp. St Petersburg.', 'Etymology (Latin/Greek)': 'Latin, caspius = of or belonging to the Caspian Sea', 'Full Description': "On page 475, Pallas describes in Latin 'CULEX caspius... Versus mare Caspium in paludosis salsis...' telling us precisely that his species occurred in salt marshes near the Caspian Sea."}, {'Mosquito Name and First Describer': 'Aedes cataphylla Dyar, 1916', 'Full Reference': 'Dyar, H.G. (1916) New Aedes from the mountains of California (Diptera, Culicidae). Insecutor Inscitiae Menstruus 4, 80-90.', 'Etymology (Latin/Greek)': 'Greek, kata = down, under; phyllon = leaf', 'Full Description': "Dyar describes the female and the egg on pages 86-87. He describes the type as 'A captured female, Fallen Leaf, Lake Tahoe, California, June 11, 1916, taken biting in the woods at the south end of the lake.' The species is presumably named after the location, Fallen Leaf, from which it was first described. A more correct translation of Fallen Leaf would have been pismenophylla, but cataphylla was chosen."}, {'Mosquito Name and First Describer': 'Aedes coluzzii Rioux, Guilvard & Pasteur, 1998', 'Full Reference': "Rioux, J.A., Guilvard, E. & Pasteur, N. (1998) Description d'Aedes (Ochlerotatus) coluzzii n.sp. (Diptera, Culicidae), espèces jumelles a du complexe detritus. Parassitologia 40, 353-60.", 'Etymology (Latin/Greek)': 'Patronymic dedication to Professor Mario Coluzzi', 'Full Description': 'Two apparently morphologically identical forms of Aedes detritus, designated sibling species A and B, were detected by isomorphic analysis of wild populations from the Camargue area of France. Species A was named Aedes coluzzii by Rioux et al. (1998) in honour of Professor Mario Coluzzi, who pioneered work on the identification of sibling species of mosquitoes using electrophoretic techniques.'}, {'Mosquito Name and First Describer': 'Aedes communis (De Geer, 1776)', 'Full Reference': "De Geer, C. (1776) Mémoires pour servir à l'histoire des Insectes 6. viii + 522pp. Stockholm Hesselberg.", 'Etymology (Latin/Greek)': 'Latin, communis = common', 'Full Description': "De Geer describes 'Cousin commun' on page 316, cousin being a word for mosquito at that time. He continued to discuss his species saying, 'Les larves de Cousins les plus communes de celles que j'ai trouvées aux environs de Leufsta dans le mois de Mai.' De Geer therefore makes clear the use of his name communis."}, {'Mosquito Name and First Describer': 'Aedes cyprius Ludlow, 1919', 'Full Reference': 'Ludlow, C.S. (1919 [1920]) New Siberian Culicidae (Diptera). Insecutor Inscitiae Menstruus 7, 151-161.', 'Etymology (Latin/Greek)': 'Latin, Cyprius = relating to Cyprus / copper', 'Full Description': "The female of this new species is described on pages 158-160 and in his last sentence Ludlow remarks that 'The insect as a whole is brilliantly copper colored and stands out conspicuously in a collection of other mosquitoes.' Pliny records that copper (cuprum) was called after Cyprus (Kypros) and Ludlow used the epithet cyprius, meaning copper coloured, to describe the species."}, {'Mosquito Name and First Describer': 'Aedes detritus (Haliday, 1833)', 'Full Reference': 'Haliday, A.H. (1833) Catalogue of Diptera occurring about Holywood in Downshire. Entomologists Magazine 1, 147-180.', 'Etymology (Latin/Greek)': 'Latin, detritus = rubbed away', 'Full Description': "Haliday includes 'Culex detritus, N.S.' in his locality list on page 148 and on page 151 he describes his species as follows: 'Culex detritus. Nigro-fuscus, abdomine pallido-annulato, ventre trifariam fusco-punctato, femoribusque basi luteis... Wings thickly clothed with dusky black scales: disk of the thorax nearly naked'. It is from this last observation that Haliday named his species."}, {'Mosquito Name and First Describer': 'Aedes diantaeus Howard, Dyar & Knab, 1912 (1913)', 'Full Reference': 'Howard, L.O., Dyar, H.G. & Knab, F. The mosquitoes of North and Central America and the West Indies. Publication 159. Vol. 2 (1912 [first issued 1913]) x + 150 plates; Vol. 4 (1917) 525-1064 pp. Washington, D.C. Carnegie Institute of Washington.', 'Etymology (Latin/Greek)': 'Greek, di- = two; Latin, anta; plural -antae = square pilasters, columns, pillars', 'Full Description': "The first mention of the specific name is in Volume 2 (plate 24, Figure 167) where the male genitalia are depicted. The palps of the male are described as 'slightly exceeding the proboscis in length, blunt at apices; vestiture brownish-black; end of long joint and last two joints slightly enlarged, with dense, moderately long, black hairs'. It is presumably the blunt nature of the palps that led to the adoption of the specific name."}, {'Mosquito Name and First Describer': 'Aedes pullatus (Coquillett, 1904)', 'Full Reference': 'Coquillett, D.W. (1904) New North American Diptera. Proceedings of the Entomological Society of Washington 6, 166-192.', 'Etymology (Latin/Greek)': 'Latin, pullatus = clad in dirty or black garments', 'Full Description': "Both the male and female are described on pages 168-169 (as Culex pullatus) and there are many references to the black coloration. In particular the opening sentence is pertinent 'Near punctor and impiger, but the bristles of the scutellum are chiefly black instead of yellow, etc' and 'Scales of palpi black...' 'Scales of abdomen black...'"}, {'Mosquito Name and First Describer': 'Aedes punctodes Dyar, 1922', 'Full Reference': 'Dyar, H.G. (1922) New mosquitoes from Alaska (Diptera, Culicidae). Insecutor Inscitiae Menstruus 10, 1-3.', 'Etymology (Latin/Greek)': 'punctor = a species of Aedes; Greek, -oides = like, resembling', 'Full Description': "The description of this new species begins on page 1 and its affinity is disclosed: 'A species of the punctor group, as shown by the male hypopygium, but differs in having the filamentum long...' The name punctodes is compounded from punctor and -oides indicating the relationship of the new species."}, {'Mosquito Name and First Describer': 'Aedes punctor (Kirby, 1837)', 'Full Reference': 'Kirby, W. (1837) The insects. In: Richardson, J. Fauna Boreali-Americana. Part 4. 325 pp. Norwich.', 'Etymology (Latin/Greek)': 'Latin, punctor = that which stings or punctures', 'Full Description': "On page 309 Kirby entitles his species 'CULEX PUNCTOR Pungent Culex', a good indication that he was aware of the fierce and persistent biting habits of this mosquito."}, {'Mosquito Name and First Describer': 'Aedes riparius Dyar & Knab, 1907', 'Full Reference': 'Dyar, H.G. & Knab, F. (1907) Descriptions of three new North American mosquitoes. Journal of the New York Entomological Society 15, 213-214.', 'Etymology (Latin/Greek)': 'Latin, riparius = of riverbanks', 'Full Description': "The description begins on page 213 and continues on page 214 where the meaning of the name is explained: 'Sixty-eight specimens... found along the banks of the Assiniboine River, among the trees.'"}, {'Mosquito Name and First Describer': 'Aedes sticticus (Meigen, 1838)', 'Full Reference': 'Meigen, J.W. (1838) Systematische Beschreibung der bekannten europäischen zweiflügeligen Insekten. Vol. 7, xii + 434 pp. Hamm.', 'Etymology (Latin/Greek)': 'Greek, stiktos = dotted, dappled; Latin, -icus = being', 'Full Description': "Meigen describes this species as Culex sticticus and notes that the abdomen is blackish with white lateral spots, 'Hinterleib schwärzlich, mit weissen Seitenflecken...' and 'Abdomine nigricante, maculis lateralibus albis...' (page 1)."}, {'Mosquito Name and First Describer': 'Aedes surcoufi (Theobald, 1912)', 'Full Reference': "Theobald, F.V. In: Surcouf, M.J. (1912) Note sur les culicides. Bulletin du Muséum nationale d'Histoire naturelle de Paris 18, 59-61.", 'Etymology (Latin/Greek)': 'Patronymic dedication to M.J. Surcouf', 'Full Description': "Theobald gives the description of this species on pages 59-60 under the heading 'Culicada Surcoufi Theobald' in an article by Surcouf. This species was one of several collected from Algeria by M.J. Surcouf who was 'chargé des travaux de zoologie au laboratoire colonial du Muséum nationale d'Histoire naturelle de Paris'."}, {'Mosquito Name and First Describer': 'Aedes thibaulti Dyar & Knab, 1910', 'Full Reference': 'Dyar, H.G. & Knab, F. (1909) (published 1910) Description of three new American mosquitoes. [Diptera, Culicidae.] Proceedings of the Entomological Society of Washington 11, 173-174.', 'Etymology (Latin/Greek)': 'Patronymic dedication to J.K. Thibault, Jr.', 'Full Description': 'The main features of the male and female of Aedes thibaulti are summarised briefly on page 174. Description is made from one male and one female from Scott, Arkansas discovered by J.K. Thibault, Jr. The species was thus named after the collector.'}, {'Mosquito Name and First Describer': 'Aedes zammitii (Theobald, 1903)', 'Full Reference': 'Theobald, F.V. (1903) A monograph of the Culicidae or mosquitoes 3. xvii + 359 pp. London. British Museum (Natural History).', 'Etymology (Latin/Greek)': 'Patronymic dedication to Dr. Zammit', 'Full Description': "Theobald named this species Acartomyia Zammitii and provided a description on pages 252-257 including figures of the adult, larva and pupa. On page 255 he included the statements 'Habitat - Malta (Dr. Zammit)' and 'Described from a series sent by Dr. Zammit'. This species is therefore named in honour of the collector."}, {'Mosquito Name and First Describer': 'Subgenus Rusticoidus Shevchenko & Prudkina, 1973', 'Full Reference': 'Shevchenko, A.K. & Prudkina, N.S. (1973) On the morphology of genitalia in mosquito males from the genus Aedes. Vestnik Zoologii 6, 40-47.', 'Etymology (Latin/Greek)': 'rusticus = a species of Aedes; Greek, -oides = like, resembling; -us = Latinized ending', 'Full Description': "In the summary in English the authors state 'The morphology of some sclerites... of male genitals from 15 species of Aedes genus of five subgenera is given. The new subgenus - Rusticoidus is distinguished and the species Aedes rejiki is included in this'. They give no reason in the text for adopting the subgeneric name Rusticoidus, and its relationship with Aedes rusticus is purely implicit."}, {'Mosquito Name and First Describer': 'Aedes krymmontanus Alekseev, 1989', 'Full Reference': 'Alekseev, E.V. (1989) The blood-sucking mosquito Aedes (Rusticoidus) krymmontanus sp. n, from the mountain forests of the Crimea. Parazitologiya 23, 173-178.', 'Etymology (Latin/Greek)': 'Ukrainian, Krym = Crimea; Latin, montanus = of a mountain', 'Full Description': "In translation Alekseev states 'On the basis of morphological, morphometric and arealogical analyses of mosquitoes collected in the mountains of Crimea, a new mosquito Aedes (Rusticoidus) krymmontanus Alekseev sp.n. is described'. The geographic location and habitat of the mosquito are thus well summarised."}, {'Mosquito Name and First Describer': 'Aedes lepidonotus (Edwards, 1920)', 'Full Reference': 'Edwards, F.W. (1920) Mosquito notes. Bulletin of Entomological Research 10, 129-137.', 'Etymology (Latin/Greek)': 'Greek, lepido = scale; Greek, noton = back; -us = Latinized ending', 'Full Description': "This species is described on pages 132-133 under the heading Ochlerotatus lepidonotus, sp. nov. On page 133 Edwards notes 'A very distinct species, with one remarkable characteristic, the possession of scales on the postnotum'."}, {'Mosquito Name and First Describer': 'Aedes quasirusticus Torres Cañamares, 1951', 'Full Reference': 'Torres Cañamares, F. (1951) Una nueva especie de Aedes. (Dipt. Cul.). EOS, Madrid 27, 79-92.', 'Etymology (Latin/Greek)': 'Latin, quasi = a sort of; rusticus = a named mosquito species', 'Full Description': "Torres Cañamares begins his description by stating that Aedes quasirusticus is a large mosquito with a dark body belonging to the subgenus Ochlerotatus, and is very similar to Aedes rusticus: 'Se trata de un mosquito grande, en su conjunto oscuro perteneciente al subgénero Ochlerotatus y muy parecido al Aed. rusticus Rossi'. The author's choice of epithet thus indicates a species like the original species (Aedes rusticus) but sufficiently different to warrant a distinct name."}, {'Mosquito Name and First Describer': 'Aedes refiki Medschid, 1928', 'Full Reference': 'Medschid, E. (1928) Über Aedes lepidonotus Edw. und Aedes Rejiki n.sp. Archiv für Schiffs- und Troppen Hygiene, Leipzig 32, 306-315.', 'Etymology (Latin/Greek)': 'Patronymic dedication to Dr. Refik Saydam', 'Full Description': "The larva and adult stages, collected from Angora (now Ankara) Turkey, are described and illustrated on pages 310-315 by 'Dr Medschid'. Although not stated explicitly, the species is almost certainly named after Dr Refik Saydam (1881-1942) who was Minister of Health at the time and who, from 1939 to 1942, served as Prime Minister of the Turkish Republic."}, {'Mosquito Name and First Describer': 'Aedes rusticus (Rossi, 1790)', 'Full Reference': 'Rossi, P. (1790) Fauna Etrusca Sistens insecta quae in provinciis Floretina at Pisana praesertim collegit. Vol. 2, 348 pp. Liburni.', 'Etymology (Latin/Greek)': 'Latin, rusticus = rural, of the country', 'Full Description': "Following his description of Culex rusticus in Latin on page 333, Rossi states that his species was found in marshy meadows around Pisa i.e. is a rural species, '...Habitat in pratis paludosis Pisanis...'"}, {'Mosquito Name and First Describer': 'Aedes subdiversus Martini, 1926', 'Full Reference': 'Martini, E. (1926) Über die Stechmücken der Umgebung von Saratow. Arbeiten der biologischen Wolga-Station, Saratow 8, 189-277.', 'Etymology (Latin/Greek)': 'Latin, sub = close to or less than, smaller than; diversus = a species of mosquito', 'Full Description': "Described on page 204 as: '24. Aedes subdiversus n. sp. Sie gleicht Aedes diversus, doch ist der Basallappen an den Hypopygien der Männchen kürzer...' (It is similar to Aedes diversus, but the basal lobe of the hypopygium in males is shorter...). Sub is used either in the sense of the new species being close to Aedes diversus or to depict that the species has a character that is smaller/shorter than that of the compared species."}, {'Mosquito Name and First Describer': 'Stegomyia Theobald, 1901', 'Full Reference': 'Theobald, F.V. in: Howard, L.O. (1901) Mosquitoes: how they live; how they carry disease; how they are classified; how they may be destroyed. New York. McClure, Phillips & Co. xv + 241 pp. / Theobald, F.V. (1901) A monograph of the Culicidae or mosquitoes. Volume 1. 424pp. London. British Museum (Natural History).', 'Etymology (Latin/Greek)': 'Greek, stego- = covered, roofed; myia = fly', 'Full Description': "Named on page 283 of the monograph as a genus (GENUS 9. -STEGOMYIA. novogen), this subgenus is described as having scales completely covering the dorsal surface of the adult fly: 'Head clothed completely with an armour of broad flat scales; mesothorax covered with either narrow-curved or spindle-shaped scales; scutellum always with broad flat scales to the middle lobe, and usually with them present on the lateral lobes; abdomen completely covered with flat scales, banded or unbanded, with white lateral spots'."}, {'Mosquito Name and First Describer': 'Aedes aegypti (Linnaeus, 1762)', 'Full Reference': 'Linnaeus, C. (1762) Zweyter Theil, enthält Beschreibungen verschiedener wichtiger Naturalien. pp. 267-606. In: Hasselquist, D.F. Reise nach Palästina in den Jahren von 1749 bis 1752. Rostock, Germany. 606pp.', 'Etymology (Latin/Greek)': 'Latin, Aegyptus = Egypt', 'Full Description': "The brief description of this species in Latin only occurs on page 470 as: 'CXXI CULEX AEGYPTI articulatiombus candidis (with bright movements) Locus, Aegyptus, Culice communi larior (Location, Egypt, larger than the common mosquito)' Linnaeus thus says nothing about the appearance of this species and his observation could apply to most species."}, {'Mosquito Name and First Describer': 'Aedes albopictus (Skuse, 1895)', 'Full Reference': 'Skuse, F.A.A. (1894) [1895] The banded mosquito of Bengal. Indian Museum Notes 3, 20.', 'Etymology (Latin/Greek)': 'Latin, albus = white; pictus = painted', 'Full Description': "In the one-page written description entitled Culex albopictus, Skuse, Sp. nov. there are many references to the white/silvery white scales of the mosquito. Among these are: 'Black with silvery-white markings... Head with silvery-white scales... tarsi, the first two joints in the fore and intermediate legs with a narrow silvery-white ring at the base; broad rings at the base of all the joints of the tarsi in the hind legs, the last joint entirely white.' The striking black mosquito painted with white markings is thus described."}, {'Mosquito Name and First Describer': 'Aedes cretinus Edwards, 1921', 'Full Reference': 'Edwards, F.W. (1921) A revision of the mosquitos of the Palaearctic Region. Bulletin of entomological Research 12, 263-351.', 'Etymology (Latin/Greek)': 'Latin, Creta = Crete', 'Full Description': "Edwards described this new species on page 325 under the heading 'Aedes (Stegomyia) cretinus, sp.n.' based upon two specimens from Crete: 'A single female in Herr Lichtwardt's collection, labelled 'Creta. v. O. Culex calopus, Mg.' and a second female from 'the Buda-Pest (sic) Museum from Amari, Crete, 4.vi. 1906 (Biró)'. Hence the species is named after the location from which it was first collected."}, {'Mosquito Name and First Describer': 'Coquillettidia Dyar, 1905', 'Full Reference': 'Dyar, H.G. (1905) Remarks on genitalic genera in the Culicidae. Proceedings of the Entomological Society of Washington 7, 42-49.', 'Etymology (Latin/Greek)': 'Greek, -id, patronymic suffix = son of, of the family of; -ia, suffix commonly used in the generic names of plants derived from personal names e.g. Fuchsia, Wisteria', 'Full Description': "Dyar dedicates his genus to Daniel William Coquillett, born January 23, 1856 in Illinois, who contributed valuable work on agricultural pests and Diptera biology and systematics. In 1896 he was raised to the office of Honorary Custodian of Diptera of the United States National Museum, a post which he held at the time of his death on July 7, 1911. Dyar does not remark on his dedication and the only reference to the name of the new genus is on page 47: 'Genus COQUILLETTIDIA, new genus...'"}, {'Mosquito Name and First Describer': 'Coquillettidia buxtoni (Edwards, 1923)', 'Full Reference': 'Edwards, F.W. (1923) Mosquito notes. -IV. Bulletin of entomological Research 14, 1-9.', 'Etymology (Latin/Greek)': 'Patronymic dedication to Patrick Alfred Buxton', 'Full Description': "On page 9 Edwards describes Taeniorhynchus (Coquillettidia) buxtoni noting that 'This species differs in many details of coloration, notably in the dark tarsi, from T. richiardii (Fic.), the only species previously known from the Palaearctic region'. Details of the collection are given as 'Palestine: Hileh, Jordan Valley, 3.ix.1922 (P.A. Buxton)'. Patrick Alfred Buxton (1892-1956) made many significant contributions to medical entomology including books on 'The Louse', 'Natural History of the Tsetse Flies' and 'Animal Life in Deserts'. He was appointed Director of the Department of Entomology at the London School of Hygiene and Tropical Medicine in 1926 and Professor of Medical Entomology at the University of London in 1933."}, {'Mosquito Name and First Describer': 'Coquillettidia richiardii (Ficalbi, 1889)', 'Full Reference': 'Ficalbi, E. (1889) Descrizione di una specie nuova (Notizie preventive sulle zanzare italiane. II. Nota preventiva). Bullettino della Società entomologica italiana 21, 50-53.', 'Etymology (Latin/Greek)': 'Patronymic dedication to Professor Richiardi', 'Full Description': "The species was described as Culex Richiardii and dedicated to Professor Richiardi on page 50 as follows: 'Dedico al Prof. Richiardi questa assai bella e pungentissima specie di zanzara italiana, che ho trovata comune assai nella region Romagnola, e specialment in Provincia di Ravenna.' [I dedicate to Prof. Richiardi this very beautiful and very pungent species of Italian mosquito, which I have found to be quite common in Emilia-Romagna and particularly in the Province of Ravenna.]"}, {'Mosquito Name and First Describer': 'Culex Linnaeus, 1758', 'Full Reference': 'Linnaeus, C. (1758) Systema naturae per regna tria naturae. Edition 10. Vol. 1. Holmiae. 824 pp.', 'Etymology (Latin/Greek)': 'Latin, culex = gnat, midge', 'Full Description': "Linnaeus names the genus Culex on page 602 of his historic work and defines it as 'Os aculeis setaceis intra vaginam flexilem' which conveys the idea of an animal having biting mouthparts with fine stylets within a flexible proboscis, a description which can be applied to all species of mosquitoes."}, {'Mosquito Name and First Describer': 'Barraudius Edwards, 1921', 'Full Reference': 'Edwards, F.W. (1921) A revision of the mosquitos of the Palaearctic Region. Bulletin of entomological Research 12, 263-351.', 'Etymology (Latin/Greek)': 'Patronymic dedication to Philip James Barraud', 'Full Description': "Edwards dedicates this sub-genus to Philip James Barraud (1879-1948) who was best known for his 1934 work on the megarhine and culicine mosquitoes of India. In his paper Edwards names 'Subgenus Barraudius, nov.' on page 332 but does not formally dedicate the taxon to Barraud. However, in the section on Culex (Barraudius) pusillus he makes the following references to him: 'I did not at first distinguish this species [Culex pusillus] from C. modestus, and it was recorded by Barraud under this name' (page 333) and 'The larva was found by Barraud in small numbers near Basra' (page 334)."}, {'Mosquito Name and First Describer': 'Culex modestus Ficalbi, 1890', 'Full Reference': 'Ficalbi, E. (1889) [1890] Descrizione di una specie nuova. Zanzara di colorito modesto Culex modestus n sp. (Notizie preventive sulle zanzare italiane. IV. Nota preventiva (1)). Bullettino della Società entomologica italiana 21, 93-94.', 'Etymology (Latin/Greek)': 'Latin, modestus = unassuming, modest, unpretentious, moderate', 'Full Description': "As Ficalbi states in the title on page 93, 'Zanzara di colorito modesto' and on page 94, 'il colorito modesto e molto uniforme...'. This is a clear indication that in his view his species was of a nondescript overall colour. He continues his description, '...scura di sopra e chiara di sotto, e mancante di bande addominali' [dark at the top and light underneath, lacking abdominal bands]."}, {'Mosquito Name and First Describer': 'Culex pusillus Macquart, 1850', 'Full Reference': "Macquart, J. (1850) Diptères exotiques nouveaux ou peu connus. 4ème supplément (1850) to the year 1849. Mémoires de la Société des sciences, de l'agriculture et des arts de Lille, 309-479.", 'Etymology (Latin/Greek)': 'Latin, pusillus = tiny', 'Full Description': "This species is described briefly in Latin and French on page 313 from specimens collected in Egypt. The general morphological features of the female are given together with a statement of its length: 'Long. 1½l'. This is indicating that the length was 1½ lignes, where one inch (un pouce) = 12 lignes. In nineteenth century France, une ligne = 0.225 cm and so the specimen described was only a third of a centimetre in length which clearly influenced Macquart in his choice of name, referring to it as 'tiny'."}, {'Mosquito Name and First Describer': 'Culex brumpti Galliard, 1931', 'Full Reference': 'Galliard, R. (1931) Culex brumpti, n. sp. Moustique nouveau trouvé en Corse. Annales de Parasitologie humaine et comparée 9, 134-139.', 'Etymology (Latin/Greek)': 'Patronymic dedication to Alexandre Joseph Emile Brumpt', 'Full Description': 'Galliard describes the larva, male and female of this species from Corsica and illustrates the characteristic features of the larva, male wing and male hypopygium. However he makes no reference to Emile Brumpt, after whom he clearly named the species. Alexandre Joseph Emile Brumpt (1877-1951) was one of the most distinguished parasitologists of all time. His Précis de Parasitologie was a standard work from the first edition in 1910 to the sixth edition in 1949. In 1903 he was a member of an expedition to Africa in which he formulated the hypothesis that the tsetse fly, Glossina palpalis, might be the vector of human trypanosomiasis.'}, {'Mosquito Name and First Describer': 'Culex laticinctus Edwards, 1913', 'Full Reference': 'Edwards, F.W. (1913) Diptera of the Lake of Tiberias. Journal of the Asiatic Society of Bengal (N.S.) 9, 48-51.', 'Etymology (Latin/Greek)': 'Latin, latus = wide; cinctus = girdle', 'Full Description': "Edwards describes this new species on pages 49 and 50. Under the heading Remarks, he states 'This species comes near C. pipiens, from which, however, it is abundantly distinct by the... broader and whiter abdominal bands...' Although not alluding to this character specifically, it would appear that this feature was responsible for Edward's naming of the species. Later, in 1921 in his classic work on the mosquitoes of the Palaearctic Region he notes 'This species differs most markedly from C. pipiens... in the pure white abdominal bands, which are as broad as or broader than the dark bands which alternate with them.'"}, {'Mosquito Name and First Describer': 'Culex mimeticus Noè, 1899', 'Full Reference': 'Noè, G. (1899) Contribuzione allo studio dei Culicidi. Bullettino della Società entomologica italiana 31, 235-262.', 'Etymology (Latin/Greek)': 'Greek, mimetic = imitation, mimic; -us = Latinised suffix', 'Full Description': "This species is first mentioned on page 238 and is described in Italian on pages 240 to 243. Noè describes similarities between this species and Anopheles superpictus, especially the wings, so much so that they could easily be confused: 'Intanto è bene notare come le ali del C. mimeticus siano quelle che giustificano il nome dato a questa specie, inquantochè, a prima vista, si possono scambiare per le ali dell'Anopheles superpictus, Grassi; altre poi sono le somiglianze tra le due specie, talchè l'inganno è tutt'altro che difficile.' This explains his use of the name mimeticus to indicate his perception of the close similarity of this new species to another."}, {'Mosquito Name and First Describer': 'Culex perexiguus Theobald, 1903', 'Full Reference': 'Theobald, F.V. (1903) A monograph of the Culicidae or mosquitoes. Vol. 3. xvii + 359 pp. London. British Museum (Natural History).', 'Etymology (Latin/Greek)': 'Latin, perexiguus = very small', 'Full Description': "This species is described on pages 199-201. On page 200 Theobald gives the length of both the male and female as 3mm and remarks on the small size of the species: 'It is a small, delicate mosquito, resembling to some extent Culex nigritulus Zetterstedt...'"}, {'Mosquito Name and First Describer': 'Culex pipiens Linnaeus, 1758', 'Full Reference': 'Linnaeus, C. (1758) Systema naturae per regna tria naturae. Edition 10. Vol. 1. 824 pp. Holmiae.', 'Etymology (Latin/Greek)': 'Latin, pipiens = piping', 'Full Description': "Linnaeus named pipiens as the first of his six species of Culex on page 602. On the following page he uses the phrase 'Insectum pipiens, pungens' conveying that this insect made a shrill or piping sound in flight and also that it 'bit'. This is a description that could be applied to a wide range of mosquito species."}, {'Mosquito Name and First Describer': 'Culex pipiens form molestus Forskål, 1775', 'Full Reference': 'Forskål, P. (1775) Descriptiones animalium avium, amphibiorum, piscium, insectorum, vermium; quae in itinere orientali observavit. Havniae, Molleri. 164pp.', 'Etymology (Latin/Greek)': 'Latin, molestus = troublesome, annoying', 'Full Description': "At the end of his morphological description of Culex molestus, Forskål relates that this species is 'extremely abundant at Rosetta, Kahira and Alexandria and is troublesome at night for sleepers and can scarcely be kept away except for a well closed curtain'. The original Latin is (page 85): 'Rosettae, Kahirae et Alexandriae immensa copia, nocte incommodus dormientibus et vix arcendus nisi cortina bene clausa.'"}, {'Mosquito Name and First Describer': 'Culex theileri Theobald, 1903', 'Full Reference': 'Theobald, F.V. (1903) A monograph of the Culicidae or mosquitoes. Vol. 3. xvii + 359 pp. London. British Museum (Natural History).', 'Etymology (Latin/Greek)': 'Patronymic dedication to Sir Arnold Theiler', 'Full Description': "Theobald gives his description of this species on pages 187-189. On the last page of his account he makes the following reference 'Habitat. - Pretoria (Dr. Theiler)...'. The 'Dr. Theiler' was Sir Arnold Theiler who is known to have made a large collection of mosquitoes in the Transvaal in 1901-02 and sent them to Theobald. Sir Arnold Theiler was born in Switzerland in 1867, studied at Berne and Zurich, gaining a veterinary degree in 1889. His classic work was the identification of piroplasmosis, or red water fever. He retired in 1927 and died in 1936."}, {'Mosquito Name and First Describer': 'Culex torrentium Martini, 1925', 'Full Reference': 'Martini, E. (1925) Zwei bemerkenswerte Culiciden von einem eigenartigen Biotop. Internationale Revue der Gesamten Hydrobiologie und Hydrographie 12, 333-337.', 'Etymology (Latin/Greek)': 'Latin, torrentium = rapid (from torrens = a torrent)', 'Full Description': "Martini's paper entitled 'Two noteworthy culicids from a peculiar biotope' reports his discovery of Culex larvae in pools among rocks in the bed of the River Schwartza, Germany left after flooding of the river '...in den Felsen Schwarzabettes... In einigen der Wasserlöcher fanden sich, gelegentlich vorwiegend, die Culexlarven'. On page 336 he states that the species may be named on the basis of the breeding place: 'Wegen ihres Brutplatzes mag sie Culex torrentium heißen.' Thus he named the species on the basis of the rapid water flow which created the breeding sites."}, {'Mosquito Name and First Describer': 'Subgenus Maillotia Theobald, 1907', 'Full Reference': 'Theobald, F.V. (1907) A monograph of the Culicidae or mosquitoes. Vol 4. xix + 639pp. London. British Museum (Natural History).', 'Etymology (Latin/Greek)': 'French, maillot = swaddling-clothes; -ia, suffix commonly used in generic names but normally reserved for those derived from personal names', 'Full Description': "On page 274 Theobald introduces 'GENUS MAILLOTIA. novogen. Head clothed with rather broad, large curved-scaled, upright forked scales and pyriform and flat lateral scales. Thorax clothed with large scales similar to those of the head; scutellum with short, rather broad, spindle-shaped scales. Wing scales dense; lateral ones thin. The genus is near Culex, but is quite distinct, its peculiar characters were noticed by Dr. Edmund Sergent, who suggested the name under which it is described.' Theobald does not explain the use of the name or say why Sergent suggested it, but it may be assumed that he considered the vestiture of the head and thorax to be sufficiently striking to warrant the comparison of being wrapped in swaddling clothes."}, {'Mosquito Name and First Describer': 'Culex deserticola Kirkpatrick, 1925', 'Full Reference': "Kirkpatrick, T.W. (1924) [1925] Preliminary notes on the determination of Egyptian mosquitos, with descriptions of three species new to science. Bulletin de la Société Royale Entomologique d'Égypte 8, 362-391.", 'Etymology (Latin/Greek)': 'Latin, desertus = waste; colere = to inhabit', 'Full Description': "This species is first listed on page 363 and later described on pages 378-383. There is a clear reference to the discovery of this species in a desert: 'Mr F.W. Edwards has informed me that he has received specimens of this species from the Sahara, (Beni Ounif de Figuig and other places).'"}, {'Mosquito Name and First Describer': 'Culex hortensis Ficalbi, 1889', 'Full Reference': 'Ficalbi, E. (1889) Notizie preventive sulla zanzare Italiane. Ia. Nota preventiva. Alcune generalità. Descrizione di una specie nuova Culex hortensis. Bullettino della Società entomologica Italiana 21, 20-30.', 'Etymology (Latin/Greek)': 'Latin, hortensis = of or belonging to a garden', 'Full Description': "The description of this species appears on pages 27-30 and on the last page Ficalbi says 'Ho trovato questa zanzara dalla primavera all'autunno nel giardino botanico di Pisa, avendola da larve prese in acque ferme del giardino stesso. La ho trovata poi nel giardino botanico di Siena e in diversi giardini di Firenze'. The finding of this species in gardens thus explains his choice of name."}, {'Mosquito Name and First Describer': 'Subgenus Neoculex Dyar, 1905', 'Full Reference': 'Dyar, H.G. (1905) Remarks on genitalic genera in the Culicidae. Proceedings of the Entomological Society of Washington 7, 42-49.', 'Etymology (Latin/Greek)': 'Greek, neos = new; and genus Culex', 'Full Description': "The first mention of the name Neoculex appears on page 45 in a key, '21. Leaf-like scale of apical lobe of side piece absent Neoculex' but the genus is formally introduced on page 48 'Genus NEOCULEX, new genus. This species may be separated from Culex proper on the characters given above...' The new taxon is therefore differentiated from Culex."}, {'Mosquito Name and First Describer': 'Culex impudicus Ficalbi, 1890', 'Full Reference': 'Ficalbi, E. (1890) Notizie preventive sulle zanzare Italiane. VIT. Nota preventiva. Descrizione di una specie nuova. Zanzara impudica Culex impudicus, sp.n. Bullettino della Società Entomologica Italiana 22, 81-84.', 'Etymology (Latin/Greek)': 'Latin, impudicus = impudent, shameless', 'Full Description': "Ficalbi names his 'zanzara impudica' (immodest mosquito) on the basis of the characteristic appearance of the male genitalia in which the gonocoxites are extremely prominent and carry long, stout setae: 'Caratteristicamente sviluppati gli organi copulatori maschili, che sono grossi, cordiformi, pelosi e setolosi' and 'Caratteristici sono gli organi copulatorii maschili, che, a differenza di altre zanzare, appaiono a guisa di due grossi lobi quasi cordiformi, che terminano l'addome, debordando ai lati...'"}, {'Mosquito Name and First Describer': 'Culex martinii Medschid, 1930', 'Full Reference': 'Medschid, E. (1930) Culex Martinii n. sp. Archiv für Schiffs- und Troppen Hygiene 34, 364-369.', 'Etymology (Latin/Greek)': 'Patronymic dedication to Erich Martini', 'Full Description': "Although there is no explicit dedication to Erich Martini in the species description, a note at the end of the paper translates as: 'Remarks on previous work of E. Martini. This is clearly the same species that was sent to me in 1927 by Apfelbeck from Metkovic in Yugoslavia. I was intending to publish it in the Culex section of Lindner's Handbook'. This species is therefore dedicated to the great German medical entomologist, Erich Martini (1880-1960). Born in Rostock, Martini was awarded his PhD in 1902 and his MD in 1905. In 1912 he was invited to organise a department of entomology at the Tropeninstitut in Hamburg. His more than three hundred publications between 1903 and 1959 cover many aspects of medical entomology and tropical medicine."}, {'Mosquito Name and First Describer': 'Culex territans Walker, 1856', 'Full Reference': 'Walker, F. (1856) Insecta Saundersiana: or characters of undescribed insects in the collection of William Wilson Saunders, Esq., F.R.S., F.L.S., &c. Vol. I. Diptera. 474 pp. London. John Van Voorst.', 'Etymology (Latin/Greek)': 'Latin, territans = alarming, terrifying', 'Full Description': "Morphological characteristics of Culex territans are given by Walker in both Latin and English on page 428 but no reference is made to the blood feeding habits of this species which presumably led him to refer to it as 'alarming or terrifying'. In fact, although there are records of Cx. territans feeding on humans, it has most often been found feeding on lower vertebrates."}, {'Mosquito Name and First Describer': 'Genus/Subgenus Culiseta Felt, 1904', 'Full Reference': 'Felt, E.P. (1904) Mosquitos or Culicidae of New York State. New York State Museum Bulletin 79, 239-400.', 'Etymology (Latin/Greek)': 'From Latin, culex = gnat, midge; Latin, seta = bristle', 'Full Description': "'Culiseta n. gen.' is named on page 391c but no clear definition of the name is offered. Felt includes in his description 'Larvae with pecten prolonged into setae and with stout, spined comb scales'. It would appear that these characteristics of the larva led him to select his name, although it may be that prominent setae present in the adult contributed to his choice of name."}, {'Mosquito Name and First Describer': 'Subgenus Allotheobaldia Brölemann, 1919', 'Full Reference': 'Brölemann, H.W. (1919) Sur quelque Culex des Pyrénées. II(1). Campagne 1918. Annales de la Société entomologique de France 87, 65-103.', 'Etymology (Latin/Greek)': 'Greek, allo- = other, different; and genus Theobaldia Neveu-Lemaire, 1902 (now Culiseta)', 'Full Description': "The subgenus is named by Brölemann on page 91 'ALLOTHEOBALDIA, novo subg.' On the following page he remarks on the peculiarities of his taxon, '...Allotheobaldia témoigne d'une différenciation notablement plus poussée que Theobaldia, qui lui-même est déjà plus différencié que Culicada...' Although not strictly a dedication to Theobald, as it was named after an existing genus, Frederic Vincent Theobald (1868-1930) was invited by the Trustees of the British Museum to prepare a monograph on the Culicidae of the world. By 1901 he had produced the first two volumes with subsequent volumes in 1903, 1907 and 1910."}, {'Mosquito Name and First Describer': 'Culiseta longiareolata (Macquart, 1838)', 'Full Reference': "Macquart, J. (1838) Diptères exotiques nouveaux ou peu connus. Mémoires de la Société des sciences, de l'agriculture et des arts de Lille 2, 9-225.", 'Etymology (Latin/Greek)': 'Latin, longus = long; areolatus = with open spaces', 'Full Description': "The relevant parts of the description of this species in Latin and French are as follows (page 38): 'CULEX LONGIAREOLATUS, Macq., Histoire naturelle des Canaries, Webb et Berthelot... alis cellulis submarginali prima et postica secunda aequaliter longis' and 'Ailes: première cellule sous-marginale et deuxième postérieure d'égale longueur (la base à la même hauteur), et plus longues qu'à l'ordinaire...' Macquart is indicating in his species name the elongated wing cells which he clearly describes."}, {'Mosquito Name and First Describer': 'Subgenus Culicella Felt, 1904', 'Full Reference': 'Felt, E.P. (1904) Mosquitos or Culicidae of New York State. New York State Museum Bulletin 79, 239-400.', 'Etymology (Latin/Greek)': 'Latin, culicella = a small gnat', 'Full Description': "Felt makes no reference to size in his description of his genus (page 391c). He introduces it as 'Culicella n. gen.' and follows this with a morphological description with information on the wing venation, the male genitalia and the larva."}, {'Mosquito Name and First Describer': 'Culiseta fumipennis (Stephens, 1825)', 'Full Reference': 'Stephens, J.F. (1825) Some observations on the British Tipulidae, together with descriptions of the species of Culex and Anopheles found in Britain. The Zoological Journal 1, 448-457.', 'Etymology (Latin/Greek)': 'Latin, fumus = smoke; penna = wing', 'Full Description': "Stephens gives his description of Culex fumipennis in Latin and English on page 453. The relevant sections are: 'Cu. fumipennis Mihi n. alis obscuris n. the wings obscure.' The Latin obscuris means dusky and Stephens is obviously using the English word obscure in this sense, hence fumipennis. Instead of using his surname after the species name to indicate the authority, Stephens uses the Latin mihi, the dative singular of ego, I, meaning 'to me'."}, {'Mosquito Name and First Describer': 'Culiseta litorea (Shute, 1928)', 'Full Reference': 'Shute, P.G. (1928) A new variety of Culicella morsitans (Theobald) (Diptera). The Entomologist 61, 186.', 'Etymology (Latin/Greek)': 'Latin, litoreus/-a = belonging to the seashore', 'Full Description': "This species was first reported by Shute as a variety of Culicella morsitans, as 'CULICELLA MORSITANS var. LITOREA, nov.', breeding in very saline water close to the sea. Marshall & Staley (1933) on examining further material showed distinctive hypopygia and raised litorea to specific rank. Commenting on Shute's original description: 'since the material described had originated in a coastal marsh, the varietal name litorea had been given.'"}, {'Mosquito Name and First Describer': 'Culiseta morsitans (Theobald, 1901)', 'Full Reference': 'Theobald, F.V. (1901) A monograph of the Culicidae or mosquitoes. Vol. 2. viii + 391 pp. London. British Museum (Natural History).', 'Etymology (Latin/Greek)': 'Latin, morsitans = biting', 'Full Description': "On page 8 Theobald names 'CULEX MORSITANS. n.sp.' and follows with a detailed description of the male and female. Under observations he says 'It is certainly... but closely related to C. vexans.' Theobald makes no reference to the origin of his name beyond the mention of its biting habits."}, {'Mosquito Name and First Describer': 'Culiseta ochroptera (Peus, 1935)', 'Full Reference': 'Peus, F. (1935) Theobaldia (Subg. Culicella) ochroptera sp. n., eine bisher unbekannte Stechmücke. Märkische Tierwelt (Zeitschrift für die Faunistische Erforschung der Kurmark) Berlin 1, 113-121.', 'Etymology (Latin/Greek)': 'Greek, ochros = yellow; Greek, pteron = wing', 'Full Description': "In his description of the female commencing on the first page of his paper, Peus reports on the appearance of the wing, describing its iridescent appearance with hues of red (carmine), violet and green and the scales on the outer border of the costa which are mainly pale ochre coloured and extend to the long fringe scales at the end of the wing: 'Flügel auf der ganzen Membran stark irisierend (karmin, violett, grün). c [costa] an der ganzen Außenkante mit bleichockerfarbenen Schuppen besetzt bis zu Beginn der langen fransenartigen Randschuppen kurz vor der Spitze.'"}, {'Mosquito Name and First Describer': 'Culiseta alaskaensis (Ludlow, 1906)', 'Full Reference': 'Ludlow, C.S. (1906) An Alaskan mosquito. The Canadian Entomologist 38, 326-328.', 'Etymology (Latin/Greek)': 'Alaska = country name; -ensis = belonging or pertaining to', 'Full Description': "'Theobaldia Alaskiiensis. n.sp.' is named on page 326. In a paper devoted to this new species there is a description of the male and female and discussion on its taxonomic position. Included are details of the location of the collection on page 328, which are given as 'Fort Egbert, Alaska'. Hence the name of this species."}, {'Mosquito Name and First Describer': 'Culiseta annulata (Schrank, 1776)', 'Full Reference': 'Schrank, F. von P. (1776) Beiträge zur Naturgeschichte. Leipzig. Fritsch. 137 pp.', 'Etymology (Latin/Greek)': 'Latin, annulatus = ringed', 'Full Description': "Schrank introduces his species on page 97 as 'Ringelselse' - ringed gnat - and continues 'Culex annulatus. C. niger, abdomine cingulis quinque albis, pedibus albo annulatis' and '...Über den Rumpf gehen fünf weiße Binden. Die Füße... mit schwarz und weißen Ringen bekleidet.' Schrank is thus emphasising the white abdominal bands and the black and white banded feet. Presumably both characters influenced the use of the epithet 'ringed'."}, {'Mosquito Name and First Describer': 'Culiseta bergrothi (Edwards, 1921)', 'Full Reference': 'Edwards, F.W. (1921) A synonymic list of the mosquitoes hitherto recorded from Sweden, with keys for determining the genera and species. Entomologisk Tidskrift 42, 46-52.', 'Etymology (Latin/Greek)': 'Patronymic dedication to Dr. Ernst Evald Bergroth', 'Full Description': "This species is listed on page 47 as 'Theobaldia bergrothi EDW. MS.' and is subsequently included in a key on page 50 as '4. Tarsi entirely dark... bergrothi sp.n.' There is no explanation of the name or mention of a collector. However Edwards (1921) states on page 287 in a section on Theobaldia glaphyroptera: 'I was led to regard the specimens sent to me by Drs. Bergroth and Frey as a distinct new species...' Culiseta bergrothi is therefore dedicated to Dr Bergroth. Dr Ernst Evald Bergroth (1857-1925) was a German dipterist who led and participated in a number of expeditions throughout Europe and Africa to collect insects, and was a leading authority on heteropterous bugs."}, {'Mosquito Name and First Describer': 'Culiseta glaphyroptera (Schiner, 1864)', 'Full Reference': 'Schiner, J.R. (1864) Fauna Austriaca. Die Fliegen (Diptera). Vol. 2. xxxii + 658 pp. Wien.', 'Etymology (Latin/Greek)': 'Greek, glaphyros = elegant; Greek, pteron = wing', 'Full Description': "This species is included in a key, in German, as Culex glaphyropterus on page 628 of the article. The wing is described as being nearly transparent with dark overlapping scales, and with blackish scales at the front edge of the wing forming indistinct spots. 'Flügel fast glashell, die schuppenartige Behaarung sehr dicht, dunkel, am Vorderrande fast schwarz, mit den angedeuteten Flecken.' This wings must have struck Schiner as being particularly ornate and elegant, and led him to base his naming of the new species on their appearance."}, {'Mosquito Name and First Describer': 'Culiseta subochrea (Edwards, 1921)', 'Full Reference': "Wesenberg-Lund, C. (1920-21) Contributions to the biology of the Danish Culicidae. Mémoires de l'Académie Royale des Sciences et des Lettres de Danemark, Copenhague. Section des Sciences, 8th series 7 (1). A.F. Høst & Son. Copenhagen. 210 pp.", 'Etymology (Latin/Greek)': 'Latin, sub- = almost; Greek, ochros/ochrea = yellow', 'Full Description': "In the postscript to his paper on the Danish Culicidae (page 198) under the heading Theobaldia annulata, Wesenberg-Lund writes: 'On an excursion to Amager [near Copenhagen] Mr. Kryger and I found a remarkable mosquito closely related to T. annulata; the white scales were however yellow and the black brown. After this work was sent to the press Mr. Edwards told me that the specimens were identic with specimens adapted to desert conditions and hitherto found in Mesopotamia; it may be named T. annulata var. subochrea Edw.' However the same year, Edwards (1921) elevated the variety to species level and describes T. subochrea on page 289 as 'Abdomen almost uniformly ochreous, the dark brown scales of T. annulata being replaced by light ochreous brown, and the white ones by almost the same colour'. Coloration was therefore the basis of his naming this species."}, {'Mosquito Name and First Describer': 'Orthopodomyia Theobald, 1904', 'Full Reference': 'Theobald, F.V. (1904) New Culicidae from the Federated Malay States. The Entomologist 37, 236-239.', 'Etymology (Latin/Greek)': 'Greek, orthos = straight; podos = of foot; myia = fly', 'Full Description': "Theobald names his genus at the beginning of the paper as 'Genus ORTHOPODOMYIA, nov. gen.' and on the next page (237) says '...The hind legs, when the insect is resting, are held straight out, close together and quite close to the surface upon which the fly rests, an abnormal attitude in the Culicinae'. Thus Theobald describes his 'straight-footed-fly'."}, {'Mosquito Name and First Describer': 'Orthopodomyia pulcripalpis (Rondani, 1872)', 'Full Reference': 'Rondani, C. (1872) Sulle specie Italiane del genere Culex Lin. Bullettino della Società Entomologica Italiana 4, 29-31.', 'Etymology (Latin/Greek)': 'Latin, pulcris (= pulchris) = beautiful; palpis = palps, feeler (from palpus)', 'Full Description': "Despite naming it because of its beautiful palps (which in the female are long and black with white bands), Rondani makes no reference to them. His full description is as follows (page 31): 'Sp. 9. pulcripalpis N. Abdomen fusco-lutescens, singuli segmenti dorsa nigricante bimaculato'. The species is described as 'abdomen brownish-yellow, each segment with two black spots dorsally'. Or. pulcripalpis has deep black abdominal tergites with snow-white basal bands."}, {'Mosquito Name and First Describer': 'Genus Uranotaenia Lynch Arribalzaga, 1891', 'Full Reference': 'Lynch Arribalzaga, F. (1891) Dipterologia argentina. Revista del Museo de la Plata 1, 345-377 (1890-91); continued in 2, 131-172 (1891).', 'Etymology (Latin/Greek)': 'Latin, uranus, Greek, ouranos = heaven; Latin, taenia, Greek, tainia = headband, ribbon', 'Full Description': "The generic name is first mentioned on page 351. Then on page 375 in a key, an account is given in Latin. This describes the proboscis and the wings, and continues: 'Corpus fuscum vel obscure testaceum, parum squamatum, coeruleo maculatum et vittatum URANOTAENIA'. [The body is tawny or dark brick-coloured, somewhat scaly, with a spotted sky blue band] Coeruleo means blue, particularly cerulean or azure, and is used to describe the colour of the sky and the surface of the sea. Lynch Arribalzaga used the word uranus, as part of his generic name to describe the heavenly (sky) colour of the headband (taenia)."}, {'Mosquito Name and First Describer': 'Subgenus Pseudoficalbia Theobald, 1912', 'Full Reference': 'Theobald, F.V. (1912) No. V.- Diptera, Culicidae. The Transactions of the Linnean Society of London, second series 15, 81-94.', 'Etymology (Latin/Greek)': 'Greek, pseudo- = false; Ficalbia = a genus named after Eugenio Ficalbi', 'Full Description': "Commenting upon a collection of mosquitoes from the Seychelles and dependent Islands, on page 81 Theobald remarks '...the remaining two [species] come in a new genus for which I propose the name Pseudoficalbia on account of their general resemblance to the Indian Ficalbia'. Then on page 89 he formally describes the new genus (now a subgenus of Uranotaenia). Ficalbia Theobald, 1903 was named after the Italian Eugenio Ficalbi (1858-1922) who wrote a number of papers on the Italian mosquito fauna and who discovered and described a number of mosquito species including Coquillettidia richiardii, Culex modestus, Culex hortensis and Culex impudicus."}, {'Mosquito Name and First Describer': 'Uranotaenia unguiculata Edwards, 1913', 'Full Reference': 'Edwards, F.W. (1913) 6. Tipulidae and Culicidae from the Lake of Tiberias and Damascus. Journal and Proceedings of the Asiatic Society of Bengal (New Series) 9, 47-51.', 'Etymology (Latin/Greek)': 'Latin, unguiculus = a finger or toe-nail', 'Full Description': "The short description of this species, in section six of a multi-authored work entitled A report on the biology of the Lake of Tiberius, appears on page 51. Edwards states 'Front legs not modified except that the claws are much longer than usual and unequal; they are not, however, so unequal as those of the mid legs, which are normal'. Later, under the heading Remarks, he notes 'In two respects - the unusual front claws, and the prolongation of the upper of the two lines of bluish scales to the front of the mesonotum - this species differs from all known Oriental or Ethiopian species of the genus...' Hence the species is named because of the characteristic tarsal claws or ungues."}, {'Mosquito Name and First Describer': 'Ochlerotatus japonicus japonicus (Theobald, 1901)', 'Full Reference': 'Theobald, F.V. (1901) A monograph of the Culicidae or mosquitoes. Volume 1. 424pp. London. British Museum (Natural History).', 'Etymology (Latin/Greek)': 'japonicus = a Latinization of the word Japan', 'Full Description': 'This species is described on page 385, with the type locality given as Tokyo, Japan, hence the species name, japonicus which is a Latinization of the word Japan.'}, {'Mosquito Name and First Describer': 'Anopheles pulcherrimus Theobald, 1902', 'Full Reference': 'Theobald, F.V. (1902) A Short Description of the Culicidae of India, with Descriptions of New Species of Anopheles. Proceedings of the Royal Society of London, series B 69, 367-394.', 'Etymology (Latin/Greek)': 'Latin, pulcherrimus = very beautiful', 'Full Description': "The female of this species is described on pages 369-370, the male being unknown at the time. Theobald describes the female, drawing attention to features such as 'Thorax ashy-brown with frosty grey and pale ochraceous scales' 'Wings with seven more or less distinct dark patches' 'costal border with four large black spots' 'Head creamy white in front, rich ochraceous behind' 'Thorax brown to ashy-brown, covered with broad, flat, spindle-shaped grey scales, giving it a frosty appearance'... 'mesonotum brown'... 'abdomen black'... 'legs with pale bands'. Theobald explains the use of the name pulcherrimus, saying that 'It is a very well defined and beautiful species...' At the end of the section he states that 'The name was proposed by the collectors', who are previously stated as Captain James, and Drs Christophers and Stephens."}, {'Mosquito Name and First Describer': 'Ochlerotatus nigrocanus (Martini, 1927)', 'Full Reference': 'Martini, E. (1927) Über zwei neue Stechmückenarten aus Anatolien. Archiv für Schiffs- und Tropen-hygiene Pathologie und Therapie Exotischer Krankheiten 31, 386-390.', 'Etymology (Latin/Greek)': 'Latin, nigro = to be black; canus = whitish-grey', 'Full Description': "Martini clearly named this species on account of its coloration. A description of the male is given on page 390 which contains many references to features of the mosquito that are black: 'Kopf schwarzhäutig... Augen schwarz... Thorax schwarz... Hinterleib oben schwarz'. Also there are references to whitish-grey coloration: '...Unterseite des Abdomens bei vorliegendem Stück stark beschädigt, schwarz mit einer Anzahl grauweißer Schuppen' '...Hinterleib oben schwarz, basale helle Binden sind vorhanden und auf den Seiten zu starken grauweißen Seitenflecken ausgezogen...'"}, {'Mosquito Name and First Describer': 'Ochlerotatus phoeniciae (Coluzzi & Sabatini, 1968)', 'Full Reference': 'Coluzzi, M. & Sabatini, A. (1968) Divergenze morphologiche e barriere di sterilità nel complesso Aedes mariae (Diptera, Culicidae). Rivista di Parassitologia 29, 49-70.', 'Etymology (Latin/Greek)': 'Phoenicia = ancient territory on the eastern coast of the Mediterranean, now largely in modern Lebanon', 'Full Description': "In their paper Coluzzi & Sabatini recognised three subspecies of Aedes mariae: the Tyrrhenian mariae, the Adriatic zammitii and the Middle-Eastern phoeniciae. The larva of 'Aedes (Ochlerotatus) mariae phoeniciae sottospecies nuova' is described on page 68 and the type locality is given as Beirut, Lebanon. This explains the selection of the name phoeniciae derived from Phoenicia, the ancient name for a territory on the eastern coast of the Mediterranean, now largely in modern Lebanon. Later, Coluzzi et al. (1970) elevated the subspecies to species status."}, {'Mosquito Name and First Describer': 'Culex tritaeniorhynchus Giles, 1901', 'Full Reference': 'Giles, G.M. (1901) A plea for the collective investigation of Indian Culicidae, with suggestions as to moot points for enquiry, and a prodromus of species known to the author. Journal of the Bombay Natural History Society 13, 592-610.', 'Etymology (Latin/Greek)': 'Latin, tri- = prefix indicating three; Latin, taenia, Greek, tainia = band, ribbon; Greek, rhynchos = snout', 'Full Description': "At the bottom of page 606 and continuing on to the following page, Giles writes: '45a. CULEX TRITAENIORHYNCHUS, sp.n. Wings unspotted; tarsi minutely basally banded pale ochreous; thorax fuscous; abdominal segments fuscous, with rather narrow yellowish-white basal bands. Proboscis with three ochreous bands.' The last character in this description, namely the three bands on the proboscis, clearly influenced Giles in naming this new species."}, {'Mosquito Name and First Describer': 'Culex vagans Wiedemann, 1828', 'Full Reference': 'Wiedemann, C.R.W. (1828) Aussereuropäische zweiflügelige Insecten. [Vol. 1.] xxxii + 608 pp. Hamm.', 'Etymology (Latin/Greek)': 'Latin, vagans = ranging, wandering', 'Full Description': "The morphological characteristics of the male and female of Culex vagans are described by Wiedemann in Latin and, more extensively, in German on page 545. There is also the brief statement 'Aus China' and reference to the fact that the specimens were collected in China by Dr Trentepohl. Wiedemann may have considered naming this mosquito after the country of capture but he had done this already on page 30 of his book for Anopheles sinensis, also from China. Quite why he selected vagans is not clear, but he may have been informed by the collector that the species was widely distributed."}]

def get_dataframe():
    return pd.DataFrame(DATA)
